/* Busca os dados da API */
const matches = $input.first().json.Results;
const addFlag = (name) => name === 'Brasil' ? `💛💚 ${name}` : name;
// Ajusta para horário de Brasília (UTC-3)
const toBRT = (date) => {
  const offset = -3 * 60;
  const brt = new Date(date.getTime() + offset * 60 * 1000);
  return brt.toISOString().replace('Z', '-03:00');
};

return matches
  /*Filtra só a fase de grupos*/
  .filter(match => match.StageName?.[0]?.Description === 'Primeira fase')
  /*Transforma cada jogo no formato padrão*/
  .map(match => {
    /*Pega o nome dos times*/
    const homeTeam = addFlag(match.Home?.TeamName?.[0]?.Description ?? match.PlaceHolderA ?? 'A definir');
    const awayTeam = addFlag(match.Away?.TeamName?.[0]?.Description ?? match.PlaceHolderB ?? 'A definir');
    const grupo = match.GroupName?.[0]?.Description ?? 'A definir';
    const inicio_jogo = new Date(match.Date);
    const fim_jogo = new Date(inicio_jogo.getTime() + 2 * 60 * 60 * 1000);

    return {
      json: {
        titulo: `${homeTeam} x ${awayTeam} | ${grupo}`,
        inicio: toBRT(inicio_jogo),
        fim: toBRT(fim_jogo),
        local: `${match.Stadium?.Name?.[0]?.Description ?? 'A definir'}, ${match.Stadium?.CityName?.[0]?.Description ?? ''}`.trim().replace(/,$/, ''),
        rodada: `Copa do Mundo 2026 - ${match.StageName?.[0]?.Description ?? ''}`.trim().replace(/ - $/, '')
      }
    };
  });
